# Rate limiting
class RateLimiter:
    def __init__(self, max_requests=10, window=60):
        self.max_requests = max_requests
        self.window = window
        self.requests = {}
    
    def check(self, addr):
        now = time.time()
        if addr not in self.requests:
            self.requests[addr] = []
        
        # Clean old requests
        self.requests[addr] = [t for t in self.requests[addr] if now - t < self.window]
        
        if len(self.requests[addr]) >= self.max_requests:
            return False
        
        self.requests[addr].append(now)
        return True

