class CoapServer:
    def __init__(self, port=COAP_PORT, require_auth=True):
        self.port = port
        self.resources = {}
        self.sock = None
        self.message_id = 0
        self.require_auth = require_auth
        self.rate_limiter = RateLimiter(max_requests=20, window=60)
    
    def add_resource(self, resource):
        self.resources[resource.path] = resource
    
    def start(self):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind(('0.0.0.0', self.port))
        self.sock.setblocking(False)
        print(f"CoAP server started on port {self.port}")
    
    def stop(self):
        if self.sock:
            self.sock.close()
            self.sock = None
    
    def get_path_from_options(self, options):
        path_parts = []
        for opt in options:
            if opt.number == COAP_OPTION_URI_PATH:
                try:
                    path_parts.append(opt.value.decode('utf-8'))
                except:
                    path_parts.append(str(opt.value))
        return '/' + '/'.join(path_parts) if path_parts else '/'
    
    def authenticate(self, token):
        if not self.require_auth:
            return True
        return token in ALLOWED_TOKENS
    
    def handle_request(self, msg, addr):
        # Security: Check authentication
        if not self.authenticate(msg.token):
            response = CoapMessage()
            response.version = COAP_VERSION
