# Device state
class DeviceState:
    def __init__(self):
        self.temperature = 25.0
        self.light_state = False
        self.adc = None
        self.led = None
        
        try:
            self.adc = machine.ADC(0)
            self.led = machine.Pin(2, machine.Pin.OUT)
        except:
            print("Warning: Hardware not available, using simulated values")
    
    def get_temperature(self):
        if self.adc:
            try:
                raw = self.adc.read()
                self.temperature = (raw / 1024.0) * 100.0
            except:
                pass
        return str(self.temperature)
    
    def get_light_state(self):
        return "on" if self.light_state else "off"
    
    def set_light_state(self, value):
        value = value.strip().lower()
        if value in ['on', '1', 'true']:
            self.light_state = True
            if self.led:
                self.led.on()
        elif value in ['off', '0', 'false']:
            self.light_state = False
            if self.led:
                self.led.off()

# Main application
def main():
    device = DeviceState()
    server = CoapServer(port=COAP_PORT, require_auth=True)
    
    # Add resources
    temp_resource = CoapResource(
        '/sensors/temp',
        get_handler=device.get_temperature
    )
    server.add_resource(temp_resource)
    
    light_resource = CoapResource(
        '/actuators/light',
        get_handler=device.get_light_state,
        put_handler=device.set_light_state
    )
    server.add_resource(light_resource)
    
    server.start()
    
    print("CoAP server running. Resources:")
    print("  GET /sensors/temp")
    print("  GET/PUT /actuators/light")
    print("Authentication required. Use token: 'secure123' or 'device456'")
    
    try:
        while True:
            server.process()
            time.sleep(0.01)
    except KeyboardInterrupt:
        print("\nShutting down server...")
        server.stop()

if __name__ == '__main__':
    main()